checker_dsl:
EXISTS (`compound assignment operator A`) {
  AND {
    (`A is an assignment addition operator (+=) or assignment multiplication operator (*=)`),
    EXISTS (`source expression E`) {
      (`E is the source operand of A`)
    },
    EXISTS (`destination type DT`, `source type ST`) {
      AND {
        (`DT is the type of the destination operand of A`),
        (`ST is the type of E`),
        (`DT is a numeric type (PrimitiveType or BoxedType)`),
        (`ST is a numeric type (PrimitiveType or BoxedType)`),
        (`the primitive type underlying ST is wider than the primitive type underlying DT`)
      }
    }
  }
}
